// Generated by `db pull`. Safe to edit — re-pull will not overwrite this file.
import { Database, fromExisting } from '@aws-blocks/bb-data';
import { tableMeta, type TableMeta } from './database.meta.js';
import { Scope } from '@aws-blocks/core';
import { AppSetting } from '@aws-blocks/bb-app-setting';
import { dbConnectionParameterName } from '@aws-blocks/core/db-naming';

const scope = new Scope('supabase');

const dbParameterName = process.env.BLOCKS_SSM_PARAM_DB_URL
  ?? dbConnectionParameterName(process.env.BLOCKS_STAGE ?? 'sandbox');
const dbUrl = AppSetting.fromExisting(scope, 'db-url', { name: dbParameterName, secret: true });

async function resolveConnString(): Promise<string> {
  const raw = await dbUrl.get();
  let u: URL;
  try {
    u = new URL(raw);
  } catch {
    // Not URL-parseable (e.g. an unencoded password) — pg can still parse it.
    // Skip port normalization rather than crash; set the port in your stored
    // connection string if you need a specific one.
    return raw;
  }
  if (process.env.BLOCKS_STACK_NAME) {
    u.port = '6543';
    u.searchParams.set('prepared_statements', 'false');
  } else {
    u.port = '5432';
  }
  return u.toString();
}

export const db = new Database(scope, 'db', {
  connection: fromExisting({ connectionString: { get: resolveConnString } }),
  rlsPolicy: 'enforce',
  schema: tableMeta,
});

/** Spread this into your ApiNamespace to add CRUD handlers. */
export function supabaseCrud(context: any, auth?: { requireAuth: (ctx: any) => Promise<{ userId: string }> }) {
  return db.crud<TableMeta>({
    tables: Object.keys(tableMeta) as (keyof typeof tableMeta)[],
    auth: () => {
      if (!auth) throw new Error('Auth not configured — pass auth to supabaseCrud(). See MIGRATION_GUIDE.md#auth');
      return auth.requireAuth(context);
    },
  });
}
